                for cand in candidate_pool:
                    if cand not in current_set:
                        gain = compute_hv(current_set | {cand}) - compute_hv(current_set)
                        if gain > best_gain:
                            best_gain = gain
                            best_cand = cand
                if best_cand is not None:
                    current_set.add(best_cand)
                    candidate_pool.remove(best_cand)
                else:
                    remaining = set(range(n)) - current_set
                    if remaining:
                        current_set.add(random.choice(list(remaining)))
        else:
            if best_set is not None and start == 1:
                current_set = best_set.copy()
                num_replace = max(1, k // 5)
                replace_idx = random.sample(list(current_set), num_replace)
                for idx in replace_idx:
                    current_set.remove(idx)
                    remaining = set(range(n)) - current_set
                    if remaining:
                        current_set.add(random.choice(list(remaining)))
            else:
                current_set = set(random.sample(range(n), k))
            candidate_pool = set(random.sample(range(n), min(50, n)))

        pool_size = min(50, n - k)
        if len(candidate_pool) < pool_size:
            remaining = set(range(n)) - current_set - candidate_pool
            if remaining:
                extra = random.sample(list(remaining), min(pool_size - len(candidate_pool), len(remaining)))
                candidate_pool.update(extra)

        for _ in range(30):
            hv = compute_hv(current_set)
            contributions = {idx: hv - compute_hv(current_set - {idx}) for idx in current_set}
            low = sorted(contributions.keys(), key=lambda x: contributions[x])[:max(1, k//3)]

            improved = False
            for low_idx in low:
                farthest = farthest_points(current_set - {low_idx}, candidate_pool - current_set, 10)
                for cand in farthest:
                    gain = delta_hv(current_set, low_idx, cand)
                    if gain > 0:
                        current_set = (current_set - {low_idx}) | {cand}
                        improved = True
                        break
                if improved:
                    break
            if not improved:
                break

        hv = compute_hv(current_set)
        for idx in current_set:
            best_gain = -np.inf
            best_cand = None
            for cand in candidate_pool - current_set:
                gain = delta_hv(current_set, idx, cand)
                if gain > best_gain:
                    best_gain = gain
                    best_cand = cand
            if best_gain > 0:
                current_set = (current_set - {idx}) | {best_cand}
                hv += best_gain

        if hv > best_hv:
            best_hv = hv
            best_set = current_set

    if best_set is None:
        indices = random.sample(range(n), k)
        return points[indices]

    selected_indices = list(best_set)
    if len(selected_indices) != k:
        if len(selected_indices) > k:
            contributions = {idx: best_hv - compute_hv(best_set - {idx}) for idx in best_set}
            top_k = sorted(contributions.keys(), key=lambda x: contributions[x])[-k:]
            selected_indices = top_k
        else:
            remaining = set(range(n)) - best_set
            extra = random.sample(list(remaining), k - len(selected_indices))
            selected_indices.extend(extra)

    return points[selected_indices]
